  `POLICY_CATEGORY` varchar(100) DEFAULT NULL,
  `APPLICABLE_FLOWS` varchar(100) DEFAULT NULL,
  `GATEWAY_TYPES` varchar(255) DEFAULT NULL,
  `API_TYPES` varchar(255) DEFAULT NULL,
