INSERT INTO `AM_OPERATION_POLICY` VALUES (1,NULL,'jsonFault','v1','3e41d5ba-668f-43a1-9d3f-80b84dae5da9','JSON Fault','This policy allows you to get an output of the fault message in JSON','[]','Mediation','[fault]','[Synapse]','[HTTP]','9323959311bb0ae77add3ad039765e7a','carbon.super'),(2,NULL,'addLogMessage','v1','855a883c-11fa-44d6-bedb-1c97def65f90','Log Policy','This policy allows you to log the important details of the request','[]','Mediation','[request, response, fault]','[Synapse]','[HTTP]','2e5a48736d4d9b5fb6c53c6d61ef2348','carbon.super'),(3,NULL,'applyAcceptHeader','v1','b72cf7b9-de1b-46ff-84d5-709ff8eb2d04','Apply Accept Header','This policy allows you to apply the Accept header','[]','Mediation','[request]','[Synapse]','[HTTP]','b84c6cd3870a35269869a1bd23c95a04','carbon.super'),(4,NULL,'ccCallInterceptorService','v1','99e6468c-4453-4e97-85f2-c23ea33ec2ec','Call Interceptor Service','This policy allows you to call an interceptor service for a request message','[\n  {\n    \"name\": \"interceptorServiceURL\",\n    \"displayName\": \"Service URL\",\n    \"description\": \"Interceptor Service URL\",\n    \"validationRegex\": \"^(([\\\\w+]+\\\\:\\\\/\\\\/)?([\\\\w\\\\d-]+\\\\.)*[\\\\w-]+([\\\\.\\\\:]\\\\w+)*([\\\\/\\\\?\\\\\\u003d\\\\\\u0026\\\\#\\\\.]?[\\\\w-]+)*\\\\/?)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"includes\",\n    \"displayName\": \"Includes to Payload\",\n    \"description\": \"Includes a comma separated list of items (for example: request_header, request_body, response_header, response_body) to the request payload of interceptor service\",\n    \"validationRegex\": \"^(([a-zA-Z\\\\d_][a-zA-Z\\\\d_\\\\-]*)(,[a-zA-Z\\\\d_][a-zA-Z\\\\d_\\\\-]*)*)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request, response]','[ChoreoConnect]','[HTTP]','15c0695864c47421b1377a05479c1f51','carbon.super'),(5,NULL,'preserveAcceptHeader','v1','7bb2f6bc-d6fb-496a-853c-f8e4f4321d17','Preserve Accept Header','This policy allows you to preserve the Accept header','[]','Mediation','[request]','[Synapse]','[HTTP]','cdf9f6415858ac80a91d67879eced0dc','carbon.super'),(6,NULL,'removeHeader','v1','a312c0e3-dfc1-4f3d-9338-ba18712dbee1','Remove Header','This policy allows you to remove a header from the request','[\n  {\n    \"name\": \"headerName\",\n    \"displayName\": \"Header Name\",\n    \"description\": \"Name of the header to be removed\",\n    \"validationRegex\": \"^([a-zA-Z_][a-zA-Z\\\\d_\\\\-\\\\ ]*)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request, response, fault]','[Synapse]','[HTTP]','39132cf460be5083812821457ba8b520','carbon.super'),(7,NULL,'debugRequestFlow','v1','43f8f426-7d4e-4ae4-9279-9f921347a091','Debug Request Flow','This policy allows you to log the special properties of the request message for debugging purposes','[]','Mediation','[request]','[Synapse]','[HTTP]','a604b27ccd150f6fa615a40571f4c5dc','carbon.super'),(8,NULL,'xmlValidator','v1','852af3b2-30c7-4ba1-9886-fad8692c7c03','XML Validator','This policy validates the request body of the XML message','[]','Mediation','[request]','[Synapse]','[HTTP]','6096f235f102b175377aed40cc373f3e','carbon.super'),(9,NULL,'rewriteResourcePath','v3','60d2df8c-9a53-4ffb-b641-2c37a5ef4b12','Rewrite Resource Path','This policy allows you to rewrite the resource path of a request','[\n  {\n    \"name\": \"newResourcePath\",\n    \"displayName\": \"New Resource Path\",\n    \"description\": \"Name of the new resource path\",\n    \"validationRegex\": \"^/?([a-zA-Z0-9!@#\\\\$%\\\\^\\\\\\u0026*\\\\)\\\\(+\\u003d._\\\\-~:,\\\\?{}/]*)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"includeQueryParams\",\n    \"displayName\": \"Include Query Parameters\",\n    \"description\": \"Select whether to include exiting query params to the new resource path\",\n    \"validationRegex\": \"^(true|false)$\",\n    \"type\": \"Boolean\",\n    \"defaultValue\": \"true\",\n    \"allowedValues\": [],\n    \"required\": false\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','008b59884f410af7e12be3b35009df7a','carbon.super'),(10,NULL,'jwtClaimBasedAccessValidator','v1','7d17e064-d33e-46ec-9df3-ae842275578b','JWT claim based access validator','This policy validates configured claim name and value in this policy with the claim name and value sent in the JWT access token to grant access to the API resource.','[\n  {\n    \"name\": \"accessVerificationClaim\",\n    \"displayName\": \"Access verification claim name\",\n    \"description\": \"This should be the name the custom claim which is expected in the JWT access token.\",\n    \"validationRegex\": \"^[a-zA-Z_]+$\",\n    \"type\": \"String\",\n    \"defaultValue\": \"aut\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"accessVerificationClaimValue\",\n    \"displayName\": \"Access verification claim value\",\n    \"description\": \"This should be the value of a custom claim which is expected in the JWT access token.\",\n    \"type\": \"String\",\n    \"defaultValue\": \"APPLICATION\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"accessVerificationClaimValueRegex\",\n    \"displayName\": \"Access verification claim value regex\",\n    \"description\": \"If a regex is provided, the claim values will be matched using this regex. Otherwise they will be checked for equality.\",\n    \"type\": \"String\",\n    \"defaultValue\": \"\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"shouldAllowValidation\",\n    \"displayName\": \"Allow flow when claims are not matching\",\n    \"description\": \"Tick this to allow the flow when the claims are not matching. Keeping this un-ticked will allow the flow only when the claims are matched.\",\n    \"type\": \"Boolean\",\n    \"defaultValue\": \"false\",\n    \"allowedValues\": [],\n    \"required\": false\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','dab8427bfc48f3afb9bc23c49d9b6af0','carbon.super'),(11,NULL,'debugResponseFlow','v1','fd706d4e-cc08-4eb5-9d22-9d9094a1ea45','Debug Response Flow','This policy allows you to log the special properties of the response message for debugging purposes','[]','Mediation','[response]','[Synapse]','[HTTP]','532a53263c874ad18e82272e4b8ad945','carbon.super'),(12,NULL,'xmlToJson','v1','3dd47b79-1e7c-461c-bc28-94b25b924223','XML to JSON','This policy allows the user to change the payload from XML to JSON','[]','Mediation','[request, response]','[Synapse]','[HTTP]','63478d64f250ef4ade262382c24ea783','carbon.super'),(13,NULL,'disableChunking','v1','2e7a25b9-249d-4d53-9d88-ee340b10ee1f','Disable Chunking','This policy disables chunking of the payload','[]','Mediation','[request, response]','[Synapse]','[HTTP]','f00340cf71d5f294d957b2817aaf9a11','carbon.super'),(14,NULL,'setToHeader','v1','d8f5d8ed-1eff-434c-82b4-a4a6d1c7ea36','Set To Header','This policy allows the user to set the To header','[\n  {\n    \"name\": \"value\",\n    \"displayName\": \"To Header Value\",\n    \"description\": \"This is the value of the To header\",\n    \"validationRegex\": \"(.*?)\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','b61b2987ce3f3ec7a360ae09754d4cc2','carbon.super'),(15,NULL,'addHeader','v2','dee06cd2-2c0c-49d9-94f9-ef60b0450d84','Add Header','This policy allows you to add a new header to the request','[\n  {\n    \"name\": \"headerName\",\n    \"displayName\": \"Header Name\",\n    \"description\": \"Name of the header to be added\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"headerValue\",\n    \"displayName\": \"Header Value\",\n    \"description\": \"Value of the header\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request, response, fault]','[Synapse]','[HTTP]','976eb48df78f6bcc899db7de7d5b4c79','carbon.super'),(16,NULL,'jsonToXML','v1','22a90952-4da7-4407-bb52-79f92afe878d','JSON to XML','This policy allows you to change the payload from JSON to XML','[]','Mediation','[request, response]','[Synapse]','[HTTP]','d5707ada4614c348ddc78e95fb784dbb','carbon.super'),(17,NULL,'BackEndJWT','v1','4b0a89c2-b225-4cef-8781-74dfece53cc3','Backend JWT','This policy allows you to enable backend jwt','[\n  {\n    \"name\": \"encoding\",\n    \"displayName\": \"Encoding\",\n    \"description\": \"Encoding of the JWT token\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"Enum\",\n    \"allowedValues\": [\n      \"Base64\",\n      \"Base64Url\"\n    ],\n    \"required\": true\n  },\n  {\n    \"name\": \"header\",\n    \"displayName\": \"Header Name\",\n    \"description\": \"Header of the JWT token\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"String\",\n    \"defaultValue\": \"X-JWT-Assertion\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"signingAlgorithm\",\n    \"displayName\": \"Signing Algorithm\",\n    \"description\": \"Signing algorithm of the JWT token\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"Enum\",\n    \"allowedValues\": [\n      \"SHA256withRSA\",\n      \"NONE\"\n    ],\n    \"required\": true\n  },\n  {\n    \"name\": \"tokenTTL\",\n    \"displayName\": \"Token TTL\",\n    \"description\": \"TokenTTL time to live for the backend JWT token in seconds\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"3600\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request]','[ChoreoConnect]','[HTTP]','f4def5895bb11b98ad5c2152545ab81d','carbon.super'),(18,NULL,'addQueryParam','v1','be74eec1-c1b0-447b-a629-83c896bed768','Add Query Param','This policy allows you to add a query parameter to the request','[\n  {\n    \"name\": \"paramKey\",\n    \"displayName\": \"Parameter Key\",\n    \"description\": \"Query parameter\\u0027s key in URL encoded format\",\n    \"validationRegex\": \"^([a-zA-Z_\\\\%][a-zA-Z\\\\d_\\\\-\\\\ \\\\%]*)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"paramValue\",\n    \"displayName\": \"Parameter Value\",\n    \"description\": \"Query parameter\\u0027s value in URL encoded format\",\n    \"validationRegex\": \"^([a-zA-Z\\\\d_\\\\%][a-zA-Z\\\\d_\\\\-\\\\ \\\\%]*)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','9efb15a4d66291841d955a17e96132dc','carbon.super'),(19,NULL,'revokeOneTimeToken','v1','60b26ecf-0493-461c-b5b5-886951354dec','Revoke One Time Token','This policy is used to revoke one time tokens. Attach the policy to the required resource and add the \'scope\' defined in the policy to the JWT token to identify the token as a one time token ','[\n  {\n    \"name\": \"scope\",\n    \"displayName\": \"Scope\",\n    \"description\": \"The designated scope name for the JWT token in order to identify the token as a One Time Token\",\n    \"validationRegex\": \"^([a-zA-Z_][a-zA-Z\\\\d_\\\\-\\\\ ]*)$\",\n    \"type\": \"String\",\n    \"defaultValue\": \"OTT\",\n    \"allowedValues\": [],\n    \"required\": true\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','ca7c85289a0482ddccc3a2249c190fe3','carbon.super'),(20,NULL,'changeHTTPMethod','v1','fc012bf4-f91e-4703-ac3a-8e8e5e7ceec8','Change HTTP Method','This policy allows you to change the HTTP Method','[\n  {\n    \"name\": \"httpMethod\",\n    \"displayName\": \"HTTP Method\",\n    \"description\": \"Method of the HTTP request\",\n    \"validationRegex\": \"^(GET|PUT|POST|PATCH|DELETE|HEAD|OPTIONS)$\",\n    \"type\": \"Enum\",\n    \"allowedValues\": [\n      \"GET\",\n      \"PUT\",\n      \"POST\",\n      \"PATCH\",\n      \"DELETE\",\n      \"HEAD\",\n      \"OPTIONS\"\n    ],\n    \"required\": true\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','9a4227d56d2b1c983bcb660eb889caef','carbon.super'),(21,NULL,'opaPolicy','v1','19bc1595-0985-4b10-9741-6996191439fd','Validate Request with OPA','This policy allows you to validate requests based on the response from OPA policy engine. The Open Policy Agent is an open source, general-purpose policy engine that unifies policy enforcement across different technologies and systems. Before applying the policy, please make sure that the OPA policy engine is configured properly. Once a gateway receives a request, gateway will extract a predefined set of meta-data from the request and query OPA via HTTP/HTTPS. OPA Policy engine will evaluate the request meta-data against the configured policy and return it\'s validation response.Based on the response, gateway will allow or block the request.','[\n  {\n    \"name\": \"serverUrl\",\n    \"displayName\": \"OPA server URL\",\n    \"description\": \"OPA server\\u0027s URL. Sample URL: https://opa-server-host:8181/v1/data. This can be an HTTP or HTTPS endpoint. If you are using a HTTPS endpoint, make sure the relevant certificates are added to the trust-store.\",\n    \"validationRegex\": \"([\\\\w+]+\\\\://)?([\\\\w\\\\d-]+\\\\.)*[\\\\w-]+[\\\\.\\\\:]?\\\\w+([/\\\\?\\\\\\u003d\\\\\\u0026\\\\#\\\\.]?[\\\\w-]+)*/?\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"accessKey\",\n    \"displayName\": \"Access Key\",\n    \"description\": \"Access key for the validation request. This is required only if the the token authentication mode is enabled at OPA server. This token will be sent along the OPA validation request as the Authorization header.\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"policy\",\n    \"displayName\": \"Policy\",\n    \"description\": \"Policy to be validated\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"rule\",\n    \"displayName\": \"Rule\",\n    \"description\": \"Rule to validate the policy\",\n    \"type\": \"String\",\n    \"defaultValue\": \"allow\",\n    \"allowedValues\": [],\n    \"required\": true\n  },\n  {\n    \"name\": \"sendAccessToken\",\n    \"displayName\": \"Send access token\",\n    \"description\": \"Select whether to send access token to the OPA payload.\",\n    \"validationRegex\": \"^(true|false)$\",\n    \"type\": \"Boolean\",\n    \"defaultValue\": \"false\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"additionalProperties\",\n    \"displayName\": \"Additional properties\",\n    \"description\": \"Additional message context (request context) properties to be included in the OPA input. Add these properties in a comma separated list. Provided properties will be added to the OPA input payload after retrieving the values from the message context.\",\n    \"validationRegex\": \"^(([a-zA-Z\\\\d_][a-zA-Z\\\\d_\\\\-]*)(,[a-zA-Z\\\\d_][a-zA-Z\\\\d_\\\\-]*)*)$\",\n    \"type\": \"String\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"maxOpenConnections\",\n    \"displayName\": \"Max open connections\",\n    \"description\": \"Maximum number of open HTTP connections between the OPA server and gateway.\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"500\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"connectionTimeout\",\n    \"displayName\": \"Connection timeout\",\n    \"description\": \"Connection timeout in seconds for the connection between the OPA server and gateway.\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"30\",\n    \"allowedValues\": [],\n    \"required\": false\n  }\n]','Security','[request]','[Synapse]','[HTTP]','ddecd148568588e6f6a14167c35035c0','carbon.super'),(22,NULL,'debugJsonFault','v1','6037bd3d-78c7-4fb4-8a9d-7ea55b74d4a6','Debug JSON Fault','This policy allows you to debug the fault payload in JSON format','[]','Mediation','[fault]','[Synapse]','[HTTP]','11c8c70eda6750e3a3c63f45cc422053','carbon.super'),(23,NULL,'jsonValidator','v1','3c9b7988-7a31-4551-b11b-b1580db4f025','JSON Validator','This policy validates the request body of the JSON message','[\n  {\n    \"name\": \"maxPropertyCount\",\n    \"displayName\": \"Max Property Count\",\n    \"description\": \"Maximum number of properties allowed in the json payload\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"100\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"maxStringLength\",\n    \"displayName\": \"Max String Length\",\n    \"description\": \"Maximum length of a string in the json payload\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"100\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"maxArrayElementCount\",\n    \"displayName\": \"Max Array Element Count\",\n    \"description\": \"Maximum number of array elements allowed in the json payload\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"100\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"maxKeyLength\",\n    \"displayName\": \"Max Key Length\",\n    \"description\": \"Maximum length of a key allowed in the json payload\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"100\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"maxJsonDepth\",\n    \"displayName\": \"Max Json Depth\",\n    \"description\": \"Maximum depth of the json payload\",\n    \"validationRegex\": \"^\\\\d{1,3}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"100\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"requestMessageBufferSize\",\n    \"displayName\": \"Request message buffer size\",\n    \"description\": \"Request message buffer size\",\n    \"validationRegex\": \"^\\\\d{1,4}$\",\n    \"type\": \"Integer\",\n    \"defaultValue\": \"1024\",\n    \"allowedValues\": [],\n    \"required\": false\n  },\n  {\n    \"name\": \"jsonSchemaValidator\",\n    \"displayName\": \"Json schema validator\",\n    \"description\": \"Json schema validator implementation class\",\n    \"validationRegex\": \"^([a-zA-Z_$][a-zA-Z\\\\d_$.]*)$\",\n    \"type\": \"String\",\n    \"defaultValue\": \"org.wso2.carbon.apimgt.gateway.mediators.JsonSchemaValidator\",\n    \"allowedValues\": [],\n    \"required\": false\n  }\n]','Mediation','[request]','[Synapse]','[HTTP]','9a8e9d6af5e8ecef3cacc0e6f0078900','carbon.super'),(24,NULL,'regexPolicy','v1','70d209a7-3e26-43d0-b5da-24ea7d49228b','Regex Policy','This is a predefined Regular Expression policy that validates content based on the pattern you define. The regex policy builds the entire message and performs string processing to find potentially harmful constructs underneath the message body. This drops the performance of 10KB messages for 300 concurrent users by 3.6 times than the normal flow. The performance decrease may accelerate along with the message size','[]','Mediation','[request]','[Synapse]','[HTTP]','a4c812ab5f1118d8e8aecc5f01ce1b06','carbon.super'),(25,NULL,'BackEndJWT','v1','42553ff9-bd2e-44fd-bd9b-2a95a74c53b8','Backend JWT','This policy allows you to enable backend jwt','[\n  {\n    \"name\": \"encoding\",\n    \"displayName\": \"Encoding\",\n    \"description\": \"Encoding of the JWT token\",\n    \"validationRegex\": \"^.+$\",\n    \"type\": \"Enum\",\n    \"allowedValues\": [\n      \"Base64\",\n      \"Base64Url\"\n    ],\n    \"required\":