INSERT INTO `AM_OPERATION_POLICY_DEFINITION` VALUES (1,'bea0eb66-dc69-49d0-be2b-b8f6427582c7',NULL,NULL,_binary '<log level=\"custom\">\n    <property name=\"STATUS\" value=\"Executing custom \'fault\' sequence\"/>\n    <property name=\"ERROR_CODE\" expression=\"get-property(\'ERROR_CODE\')\"/>\n    <property name=\"ERROR_MESSAGE\" expression=\"get-property(\'ERROR_MESSAGE\')\"/>\n</log>\n<payloadFactory>\n    <format>\n        <am:fault xmlns:am=\"http://wso2.org/apimanager\">\n            <am:code>$1</am:code>\n            <am:type>Status report</am:type>\n            <am:message>Runtime Error</am:message>\n            <am:description>$2</am:description>\n        </am:fault>\n    </format>\n    <args>\n        <arg expression=\"$ctx:ERROR_CODE\"/>\n        <arg expression=\"$ctx:ERROR_MESSAGE\"/>\n    </args>\n</payloadFactory>\n<filter xpath=\"$ctx:CUSTOM_HTTP_SC\">\n    <then>\n        <property name=\"HTTP_SC\" expression=\"$ctx:CUSTOM_HTTP_SC\" scope=\"axis2\"/>\n    </then>\n    <else>\n        <property name=\"HTTP_SC\" value=\"500\" scope=\"axis2\"/>\n    </else>\n</filter>\n<property name=\"RESPONSE\" value=\"true\"/>\n<header name=\"To\" action=\"remove\"/>\n<property name=\"NO_ENTITY_BODY\" scope=\"axis2\" action=\"remove\"/>\n<property name=\"ContentType\" scope=\"axis2\" action=\"remove\"/>\n<property name=\"Authorization\" scope=\"transport\" action=\"remove\"/>\n<property name=\"Host\" scope=\"transport\" action=\"remove\"/>\n<property name=\"Accept\" scope=\"transport\" action=\"remove\"/>\n<property name=\"X-JWT-Assertion\" scope=\"transport\" action=\"remove\"/>\n<property name=\"messageType\" value=\"application/json\" scope=\"axis2\"/>\n<send/>\n<drop/>','Synapse','8f24a6ea66f17d6a28ed164414d52a65'),(2,'46d9e567-14d8-4ab2-9a9c-1320f3e7b2a9',NULL,NULL,_binary '<log level=\"full\">\n    <property name=\"MESSAGE\" value=\"MESSAGE\"/>\n</log>','Synapse','f38cb7c1597d4901ff86b6970d9943c5'),(3,'06d6b10e-a61f-4217-99c1-dc43f5f4c8bd',NULL,NULL,_binary '